"use client"

import { useState } from "react"
import Image from "next/image"
import { Button } from "@/components/atoms"
import { deleteLineItem, updateLineItem } from "@/lib/data/cart"
import { EnrichedCart, EnrichedCartItem } from "@/lib/services/cart-enrichment"
import { formatAmount } from "@/lib/helpers/money"
import { InventoryValidator } from "./InventoryValidator"

interface Props {
  enrichedCart: EnrichedCart
}

interface EnhancedCartItemProps {
  item: EnrichedCartItem
  currencyCode: string
}

function EnhancedCartItem({ item, currencyCode }: EnhancedCartItemProps) {
  const [updating, setUpdating] = useState(false)
  const [deleting, setDeleting] = useState(false)

  const handleUpdateQuantity = async (quantity: number) => {
    if (quantity <= 0) {
      return handleDelete()
    }
    
    setUpdating(true)
    try {
      await updateLineItem({ lineId: item.id, quantity })
    } catch (error) {
      console.error('Error updating cart item:', error)
    } finally {
      setUpdating(false)
    }
  }

  const handleDelete = async () => {
    setDeleting(true)
    try {
      await deleteLineItem(item.id)
    } catch (error) {
      console.error('Error deleting cart item:', error)
    } finally {
      setDeleting(false)
    }
  }

  const cardData = item.catalog_enrichment?.card
  const printData = item.catalog_enrichment?.print
  const gameData = item.catalog_enrichment?.game
  const setData = item.catalog_enrichment?.set
  const sellerData = item.seller_info

  return (
    <div className={`p-4 border rounded-lg bg-white ${deleting ? 'opacity-50' : ''}`}>
      <div className="flex gap-4">
        {/* Card Image */}
        <div className="flex-shrink-0">
          {printData?.image_small ? (
            <Image
              src={printData.image_small}
              alt={cardData?.name || item.title}
              width={80}
              height={112}
              className="rounded-lg border object-cover"
            />
          ) : (
            <div className="w-20 h-28 bg-gray-200 rounded-lg border flex items-center justify-center">
              <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
            </div>
          )}
        </div>

        {/* Card Details */}
        <div className="flex-grow">
          <div className="flex justify-between items-start">
            <div>
              <h3 className="font-semibold text-lg text-gray-900">
                {cardData?.name || item.title}
              </h3>
              
              {/* Game and Set Info */}
              <div className="flex items-center gap-2 mt-1">
                {gameData && (
                  <span className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded-full font-medium">
                    {gameData.name}
                  </span>
                )}
                {setData && (
                  <span className="text-sm text-gray-600">
                    {setData.name}
                  </span>
                )}
              </div>

              {/* Card Condition & Language */}
              <div className="flex items-center gap-3 mt-2">
                {item.catalog_enrichment?.condition && (
                  <div className="flex items-center gap-1">
                    <span className="text-xs text-gray-500">Condition:</span>
                    <span className="text-sm font-medium text-gray-900">
                      {item.catalog_enrichment.condition}
                    </span>
                  </div>
                )}
                {item.catalog_enrichment?.language && (
                  <div className="flex items-center gap-1">
                    <span className="text-xs text-gray-500">Language:</span>
                    <span className="text-sm font-medium text-gray-900">
                      {item.catalog_enrichment.language}
                    </span>
                  </div>
                )}
                {item.catalog_enrichment?.finish && item.catalog_enrichment.finish !== 'NORMAL' && (
                  <span className="px-2 py-1 bg-yellow-100 text-yellow-800 text-xs rounded-full">
                    {item.catalog_enrichment.finish}
                  </span>
                )}
              </div>

              {/* Seller Info */}
              {sellerData && (
                <div className="flex items-center gap-2 mt-2">
                  <span className="text-xs text-gray-500">Sold by:</span>
                  <div className="flex items-center gap-1">
                    <span className="text-sm font-medium text-gray-900">
                      {sellerData.name}
                    </span>
                    {sellerData.verified && (
                      <svg className="w-4 h-4 text-green-500" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                      </svg>
                    )}
                    {sellerData.type === 'consumer_seller' && (
                      <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-xs rounded">
                        Individual
                      </span>
                    )}
                    {sellerData.rating && (
                      <span className="text-sm text-gray-600">
                        ★ {sellerData.rating.toFixed(1)}
                      </span>
                    )}
                  </div>
                </div>
              )}
            </div>

            {/* Price and Actions */}
            <div className="text-right">
              <div className="text-lg font-bold text-gray-900">
                {formatAmount(item.total, currencyCode)}
              </div>
              {item.quantity > 1 && (
                <div className="text-sm text-gray-600">
                  {formatAmount(item.unit_price, currencyCode)} each
                </div>
              )}
            </div>
          </div>

          {/* Quantity Controls */}
          <div className="flex items-center justify-between mt-4">
            <div className="flex items-center gap-2">
              <span className="text-sm text-gray-600">Quantity:</span>
              <div className="flex items-center border rounded-lg">
                <button
                  onClick={() => handleUpdateQuantity(item.quantity - 1)}
                  disabled={updating || deleting}
                  className="p-2 hover:bg-gray-100 disabled:opacity-50"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                  </svg>
                </button>
                <span className="px-4 py-2 border-x text-center min-w-[50px]">
                  {item.quantity}
                </span>
                <button
                  onClick={() => handleUpdateQuantity(item.quantity + 1)}
                  disabled={updating || deleting}
                  className="p-2 hover:bg-gray-100 disabled:opacity-50"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                  </svg>
                </button>
              </div>
            </div>

            <button
              onClick={handleDelete}
              disabled={updating || deleting}
              className="text-red-600 hover:text-red-800 text-sm disabled:opacity-50"
            >
              {deleting ? 'Removing...' : 'Remove'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

function SellerGroup({ group, currencyCode }: { group: any, currencyCode: string }) {
  return (
    <div className="mb-6">
      {/* Seller Header */}
      <div className="flex items-center justify-between p-3 bg-gray-50 rounded-t-lg border-b">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2">
            <svg className="w-5 h-5 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
            </svg>
            <span className="font-medium text-gray-900">{group.seller_name}</span>
            {group.seller_type === 'consumer_seller' && (
              <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs rounded-full">
                Individual Seller
              </span>
            )}
          </div>
          {group.seller_rating && (
            <span className="text-sm text-gray-600">
              ★ {group.seller_rating.toFixed(1)}
            </span>
          )}
        </div>
        <div className="text-right">
          <div className="text-sm text-gray-600">
            {group.item_count} item{group.item_count !== 1 ? 's' : ''}
          </div>
          <div className="font-medium text-gray-900">
            {formatAmount(group.subtotal, currencyCode)}
          </div>
        </div>
      </div>

      {/* Seller Items */}
      <div className="border-x border-b rounded-b-lg">
        {group.items.map((item: EnrichedCartItem, index: number) => (
          <div key={item.id} className={index > 0 ? 'border-t' : ''}>
            <EnhancedCartItem item={item} currencyCode={currencyCode} />
          </div>
        ))}
      </div>
    </div>
  )
}

export function EnhancedCartItems({ enrichedCart }: Props) {
  if (!enrichedCart || enrichedCart.items.length === 0) {
    return (
      <div className="text-center py-12">
        <div className="w-24 h-24 mx-auto mb-4 bg-gray-200 rounded-lg flex items-center justify-center">
          <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4m0 0L7 13m0 0l-2.5 5M7 13l2.5 5m0 0H17M17 18a2 2 0 11-4 0 2 2 0 014 0zM9 18a2 2 0 11-4 0 2 2 0 014 0z" />
          </svg>
        </div>
        <h3 className="text-lg font-semibold text-gray-900 mb-2">Your cart is empty</h3>
        <p className="text-gray-600">Start building your collection by browsing our cards.</p>
      </div>
    )
  }

  // Currency code from first item (should be consistent across cart)
  const currencyCode = enrichedCart.items[0]?.total ? 'USD' : 'USD' // Fallback to USD

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold text-gray-900">Shopping Cart</h2>
        <span className="text-sm text-gray-600">
          {enrichedCart.totals.item_count} item{enrichedCart.totals.item_count !== 1 ? 's' : ''}
        </span>
      </div>

      {/* Inventory Validation */}
      <InventoryValidator items={enrichedCart.items} />

      {/* Show items grouped by seller */}
      {enrichedCart.seller_groups.length > 0 ? (
        enrichedCart.seller_groups.map((group) => (
          <SellerGroup
            key={group.seller_id}
            group={group}
            currencyCode={currencyCode}
          />
        ))
      ) : (
        /* Fallback: Show items without grouping */
        <div className="space-y-4">
          {enrichedCart.items.map((item) => (
            <EnhancedCartItem
              key={item.id}
              item={item}
              currencyCode={currencyCode}
            />
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import { Heading, Text, useToggleState } from "@medusajs/ui"
import { setAddresses } from "@/lib/data/cart"
import compareAddresses from "@/lib/helpers/compare-addresses"
import { HttpTypes } from "@medusajs/types"
import { usePathname, useRouter, useSearchParams } from "next/navigation"
import { useActionState, useEffect } from "react"
import { Button } from "@/components/atoms"
import ErrorMessage from "@/components/molecules/ErrorMessage/ErrorMessage"
import Spinner from "@/icons/spinner"
import ShippingAddress from "@/components/organisms/ShippingAddress/ShippingAddress"
import { CheckCircleSolid } from "@medusajs/icons"
import LocalizedClientLink from "@/components/molecules/LocalizedLink/LocalizedLink"

export const CartAddressSection = ({
  cart,
  customer,
}: {
  cart: HttpTypes.StoreCart | null
  customer: HttpTypes.StoreCustomer | null
}) => {
  const searchParams = useSearchParams()
  const router = useRouter()
  const pathname = usePathname()

  const isAddress = Boolean(
    cart?.shipping_address &&
      cart?.shipping_address.first_name &&
      cart?.shipping_address.last_name &&
      cart?.shipping_address.address_1 &&
      cart?.shipping_address.city &&
      cart?.shipping_address.postal_code &&
      cart?.shipping_address.country_code
  )
  const isOpen = searchParams.get("step") === "address" || !isAddress

  const { state: sameAsBilling, toggle: toggleSameAsBilling } = useToggleState(
    cart?.shipping_address && cart?.billing_address
      ? compareAddresses(cart?.shipping_address, cart?.billing_address)
      : true
  )

  const [message, formAction] = useActionState(setAddresses, sameAsBilling)

  useEffect(() => {
    if (!isAddress) {
      router.replace(pathname + "?step=address")
    }
  }, [isAddress])

  const handleEdit = () => {
    router.replace(pathname + "?step=address")
  }

  return (
    <div className="border p-4 rounded-sm bg-ui-bg-interactive">
      <div className="flex flex-row items-center justify-between mb-6">
        <Heading
          level="h2"
          className="flex flex-row text-3xl-regular gap-x-2 items-baseline items-center"
        >
          {!isOpen && <CheckCircleSolid />} Shipping Address
        </Heading>
        {!isOpen && isAddress && (
          <Text>
            <Button onClick={handleEdit} variant="tonal">
              Edit
            </Button>
          </Text>
        )}
      </div>
      <form
        action={async (data) => {
          await formAction(data)
          router.replace(`${pathname}?step=delivery`)
        }}
      >
        {isOpen ? (
          <div className="pb-8">
            <ShippingAddress
              customer={customer}
              checked={sameAsBilling}
              onChange={toggleSameAsBilling}
              cart={cart}
            />
            <Button
              className="mt-6"
              data-testid="submit-address-button"
              variant="tonal"
            >
              Save
            </Button>
            <ErrorMessage
              error={message !== "success" && message}
              data-testid="address-error-message"
            />
          </div>
        ) : (
          <div>
            <div className="text-small-regular">
              {cart && cart.shipping_address ? (
                <div className="flex items-start gap-x-8">
                  <div className="flex items-start gap-x-1 w-full">
                    <div>
                      <Text className="txt-medium-plus font-bold">
                        {cart.shipping_address.first_name}{" "}
                        {cart.shipping_address.last_name}
                      </Text>
                      <Text>
                        {cart.shipping_address.address_1}{" "}
                        {cart.shipping_address.address_2},{" "}
                        {cart.shipping_address.postal_code}{" "}
                        {cart.shipping_address.city},{" "}
                        {cart.shipping_address.country_code?.toUpperCase()}
                      </Text>
                      <Text>
                        {cart.email}, {cart.shipping_address.phone}
                      </Text>
                    </div>
                  </div>
                </div>
              ) : (
                <div>
                  <Spinner />
                </div>
              )}
            </div>
          </div>
        )}
        {isAddress && !searchParams.get("step") && (
          <LocalizedClientLink href="/checkout?step=delivery">
            <Button className="mt-6" variant="tonal">
              Continue to Delivery
            </Button>
          </LocalizedClientLink>
        )}
      </form>
    </div>
  )
}

"use client"

import ErrorMessage from "@/components/molecules/ErrorMessage/ErrorMessage"
import { setShippingMethod } from "@/lib/data/cart"
import { calculatePriceForShippingOption } from "@/lib/data/fulfillment"
import { convertToLocale } from "@/lib/helpers/money"
import { CheckCircleSolid, ChevronUpDown, Loader } from "@medusajs/icons"
import { HttpTypes } from "@medusajs/types"
import { clx, Heading, Text } from "@medusajs/ui"
import { usePathname, useRouter, useSearchParams } from "next/navigation"
import { Fragment, useEffect, useState } from "react"
import { Button } from "@/components/atoms"
import { Modal, SelectField } from "@/components/molecules"
import { CartShippingMethodRow } from "./CartShippingMethodRow"
import { Listbox, Transition } from "@headlessui/react"
import clsx from "clsx"

// Extended cart item product type to include seller
type ExtendedStoreProduct = HttpTypes.StoreProduct & {
  seller?: {
    id: string
    name: string
  }
}

// Cart item type definition
type CartItem = {
  product?: ExtendedStoreProduct
  // Include other cart item properties as needed
}

export type StoreCardShippingMethod = HttpTypes.StoreCartShippingOption & {
  seller_id?: string
  service_zone?: {
    fulfillment_set: {
      type: string
    }
  }
}

type ShippingProps = {
  cart: Omit<HttpTypes.StoreCart, "items"> & {
    items?: CartItem[]
  }
  availableShippingMethods:
    | (StoreCardShippingMethod &
        { rules: any; seller_id: string; price_type: string; id: string }[])
    | null
}

const CartShippingMethodsSection: React.FC<ShippingProps> = ({
  cart,
  availableShippingMethods,
}) => {
  const [isLoadingPrices, setIsLoadingPrices] = useState(false)
  const [calculatedPricesMap, setCalculatedPricesMap] = useState<
    Record<string, number>
  >({})
  const [error, setError] = useState<string | null>(null)
  const [missingModal, setMissingModal] = useState(false)
  const [missingShippingSellers, setMissingShippingSellers] = useState<
    string[]
  >([])

  const searchParams = useSearchParams()
  const router = useRouter()
  const pathname = usePathname()

  const isOpen = searchParams.get("step") === "delivery"

  const _shippingMethods = availableShippingMethods?.filter(
    (sm) =>
      sm.rules?.find((rule: any) => rule.attribute === "is_return")?.value !==
      "true"
  )

  useEffect(() => {
    const set = new Set<string>()
    cart.items?.forEach((item) => {
      if (item?.product?.seller?.id) {
        set.add(item.product.seller.id)
      }
    })

    const sellerMethods = _shippingMethods?.map(({ seller_id }) => seller_id)

    const missingSellerIds = [...set].filter(
      (sellerId) => !sellerMethods?.includes(sellerId)
    )

    setMissingShippingSellers(Array.from(missingSellerIds))

    if (missingSellerIds.length > 0 && !cart.shipping_methods?.length) {
      setMissingModal(true)
    }
  }, [cart])

  useEffect(() => {
    if (_shippingMethods?.length) {
      const promises = _shippingMethods
        .filter((sm) => sm.price_type === "calculated")
        .map((sm) => calculatePriceForShippingOption(sm.id, cart.id))

      if (promises.length) {
        Promise.allSettled(promises).then((res) => {
          const pricesMap: Record<string, number> = {}
          res
            .filter((r) => r.status === "fulfilled")
            .forEach((p) => (pricesMap[p.value?.id || ""] = p.value?.amount!))

          setCalculatedPricesMap(pricesMap)
          setIsLoadingPrices(false)
        })
      }
    }
  }, [availableShippingMethods])

  const handleSubmit = () => {
    router.push(pathname + "?step=payment", { scroll: false })
  }

  const handleSetShippingMethod = async (id: string | null) => {
    setIsLoadingPrices(true)
    setError(null)

    if (!id) {
      setIsLoadingPrices(false)
      return
    }

    await setShippingMethod({ cartId: cart.id, shippingMethodId: id }).catch(
      (err) => {
        setError(err.message)
      }
    )

    setIsLoadingPrices(false)
  }

  useEffect(() => {
    setError(null)
  }, [isOpen])

  const groupedBySellerId = _shippingMethods?.reduce((acc: any, method) => {
    const sellerId = method.seller_id!

    if (!acc[sellerId]) {
      acc[sellerId] = []
    }

    acc[sellerId]?.push(method)
    return acc
  }, {})

  const handleEdit = () => {
    router.replace(pathname + "?step=delivery")
  }

  const missingSellers = cart.items
    ?.filter((item) =>
      missingShippingSellers.includes(item.product?.seller?.id!)
    )
    .map((item) => item.product?.seller?.name)

  return (
    <div className="border p-4 rounded-sm bg-ui-bg-interactive">
      {/* {missingModal && (
        <Modal
          heading="Missing seller shipping option"
          onClose={() => router.push(`/${pathname.split("/")[1]}/cart`)}
        >
          <div className="p-4">
            <h2 className="heading-sm">
              Some of the sellers in your cart do not have shipping options.
            </h2>

            <p className="text-md mt-3">
              Please remove the{" "}
              <span className="font-bold">
                {missingSellers?.map(
                  (seller, index) =>
                    `${seller}${
                      index === missingSellers.length - 1 ? " " : ", "
                    }`
                )}
              </span>{" "}
              items or contact{" "}
              {missingSellers && missingSellers?.length > 1 ? "them" : "him"} to
              get the shipping options.
            </p>
          </div>
        </Modal>
      )} */}
      <div className="flex flex-row items-center justify-between mb-6">
        <Heading
          level="h2"
          className="flex flex-row text-3xl-regular gap-x-2 items-baseline items-center"
        >
          {!isOpen && (cart.shipping_methods?.length ?? 0) > 0 && (
            <CheckCircleSolid />
          )}
          Delivery
        </Heading>
        {!isOpen && (
          <Text>
            <Button onClick={handleEdit} variant="tonal">
              Edit
            </Button>
          </Text>
        )}
      </div>
      {isOpen ? (
        <>
          <div className="grid">
            <div data-testid="delivery-options-container">
              <div className="pb-8 md:pt-0 pt-2">
                {Object.keys(groupedBySellerId).map((key) => {
                  return (
                    <div key={key} className="mb-4">
                      <Heading level="h3" className="mb-2">
                        {groupedBySellerId[key][0].seller_name}
                      </Heading>
                      <Listbox
                        value={cart.shipping_methods?.[0]?.id}
                        onChange={(value) => {
                          handleSetShippingMethod(value)
                        }}
                      >
                        <div className="relative">
                          <Listbox.Button
                            className={clsx(
                              "relative w-full flex justify-between items-center px-4 h-12 bg-component-secondary text-left  cursor-default focus:outline-none border border-border rounded-lg focus-visible:ring-2 focus-visible:ring-opacity-75 focus-visible:ring-action focus-visible:ring-offset-secondary focus-visible:ring-offset-2 focus-visible:border-action text-base-regular"
                            )}
                          >
                            {({ open }) => (
                              <>
                                <span className="block truncate">
                                  Choose delivery option
                                </span>
                                <ChevronUpDown
                                  className={clx(
                                    "transition-rotate duration-200",
                                    {
                                      "transform rotate-180": open,
                                    }
                                  )}
                                />
                              </>
                            )}
                          </Listbox.Button>
                          <Transition
                            as={Fragment}
                            leave="transition ease-in duration-100"
                            leaveFrom="opacity-100"
                            leaveTo="opacity-0"
                          >
                            <Listbox.Options
                              className="absolute z-20 w-full overflow-auto text-small-regular bg-secondary border border-border rounded-lg border-top-0 max-h-60 focus:outline-none sm:text-sm"
                              data-testid="shipping-address-options"
                            >
                              {groupedBySellerId[key].map((option: any) => {
                                return (
                                  <Listbox.Option
                                    className="cursor-pointer select-none relative pl-6 pr-10 hover:bg-component-secondary-hover py-4 border-b border-border"
                                    value={option.id}
                                    key={option.id}
                                  >
                                    {option.name}
                                    {" - "}
                                    {option.price_type === "flat" ? (
                                      convertToLocale({
                                        amount: option.amount!,
                                        currency_code: cart?.currency_code,
                                      })
                                    ) : calculatedPricesMap[option.id] ? (
                                      convertToLocale({
                                        amount: calculatedPricesMap[option.id],
                                        currency_code: cart?.currency_code,
                                      })
                                    ) : isLoadingPrices ? (
                                      <Loader />
                                    ) : (
                                      "-"
                                    )}
                                  </Listbox.Option>
                                )
                              })}
                            </Listbox.Options>
                          </Transition>
                        </div>
                      </Listbox>
                    </div>
                  )
                })}
                {cart && (cart.shipping_methods?.length ?? 0) > 0 && (
                  <div className="flex flex-col">
